import App from './App.vue'
import router from './router'
//import './plugins/element.js'
import './assets/global.css'
import VueQuillEditor from 'vue-quill-editor'
import 'quill/dist/quill.core.css'
import 'quill/dist/quill.snow.css'
import 'quill/dist/quill.bubble.css'
import Vue from 'vue'
Vue.use(VueQuillEditor)
Vue.prototype.$serveUrl='https://www.ojwxh.xyz'
Vue.prototype.$echarts=echarts
Vue.prototype.$myLoading=function(){
  this.$emit('loading',true)
  this.$nextTick(()=>{
    this.$emit('loading',false)
  })
}
Vue.$message=Element.Message
axios.defaults.baseURL=Vue.prototype.$serveUrl+'/api'
axios.interceptors.response.use(res => {
  return res.data
})
axios.interceptors.request.use(config=>{
  config.headers.authorization=window.sessionStorage.getItem('token')
  return config
})
Vue.config.productionTip = false
Vue.prototype.$http=axios
Vue.filter('dateFormat',function(orignal){
  const dt=new Date(orignal)
  const datetime=dt.toLocaleTimeString()
  const year=dt.getFullYear()
  const month=dt.getMonth()+1
  const date=dt.getDate()
  
  return year+'/'+month+'/'+date+' '+datetime
})
router.beforeEach((to,from,next)=>{
  let token=window.sessionStorage.getItem('token')
  if(to.path!='/login'){
    if(!token)return router.push({path:'/login'})
    else return next();
  }
  next()
})
new Vue({
  router,
  render: h => h(App)
}).$mount('#app')
