<template>
  <div>
    <el-breadcrumb separator-class="el-icon-arrow-right">
      <el-breadcrumb-item :to="{ path: '/index' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>评论管理</el-breadcrumb-item>
      <el-breadcrumb-item>文章评论</el-breadcrumb-item>
    </el-breadcrumb>
    <el-card>
      <div class="statusBox">
      <span>状态:</span>
      <el-select v-model="statusQuery" style="width:250px;">
        <el-option label="待审核" :value="0">
        </el-option>
        <el-option label="已审核" :value="1">
        </el-option>
      </el-select>
      <el-button type="primary" @click="handleStatusQuery">查询</el-button>
      </div>
         <div class="searchBox">
        <!-- 搜索 -->
        <el-input
          placeholder="请输入内容"
          class="input-with-select search"
          v-model="queryInfo.query"
          clearable
          @clear="getCommentList"
        >
          <el-button
            slot="append"
            icon="el-icon-search"
            @click="queryInfo.pagenum=1;getCommentList()"
          ></el-button>
        </el-input>
      </div>
    </el-card>
    <el-card class="box-card">
   
      <!--数据区-->
      <div class="card-main">
        <el-table :data="commentList.comments" border style="width: 100%">
          <el-table-column type="index" label="#" width="50"></el-table-column>
          <el-table-column prop="title" label="文章标题" width="300">
            <template slot-scope="scope">
              <el-link
                type="primary"
                :href="'http://localhost/home/article?aid='+scope.row.aid"
              >#{{scope.row.title}}</el-link>
            </template>
          </el-table-column>
          <el-table-column prop="to_comment" label="父级评论" width="180"></el-table-column>
          <el-table-column prop="content" label="评论内容" width="180"></el-table-column>
          <el-table-column prop="username" label="评论人" width="180"></el-table-column>
          <el-table-column prop="time" width="300" label="评论时间">
            <template slot-scope="scope">{{scope.row.time | dateFormat}}</template>
          </el-table-column>
          <el-table-column prop="status" label="状态">
            <template slot-scope="scope">
              <el-tag v-if="scope.row.status==1" type="success">已审批</el-tag>
              <el-tag
                v-else
                type="warning"
                @click="stateChange(scope.row._id)"
                class="clickStatus"
              >审批</el-tag>
            </template>
          </el-table-column>
          <el-table-column prop="caozuo" label="操作">
            <template slot-scope="scope">
              <el-tooltip class="item" effect="dark" content="回复" placement="top">
                <el-button
                  size="small"
                  icon="el-icon-chat-dot-square"
                  @click="showReplyDialog(scope.row._id,scope.row.aid)"
                ></el-button>
              </el-tooltip>
              <el-tooltip class="item" effect="dark" content="删除" placement="top">
                <el-button
                  type="danger"
                  size="small"
                  icon="el-icon-delete"
                  @click="deleteComment(scope.row._id)"
                ></el-button>
              </el-tooltip>
            </template>
          </el-table-column>
        </el-table>
      </div>
      <!--回复-->
      <el-dialog
        title="回复"
        :visible.sync="replyDialogVisible"
        width="30%"
        @close="handleReplyClose"
      >
        
            <el-input type="textarea" :rows="4" placeholder="请输入内容" v-model="replyForm.content"></el-input>
         
          <div class="el-form-item" style="margin-top:20px;float:right">
            <el-button @click="handleReplyClose" >取 消</el-button>
            <el-button type="primary" @click="handleReply">确 定</el-button>
            
          </div>
       <div style="clear:both"></div>
      </el-dialog>
      <!--分页-->
      <el-pagination
        @size-change="handleSizeChange"
        @current-change="handleCurrentChange"
        :current-page="queryInfo.pagenum"
        :page-size="queryInfo.pagesize"
        :page-sizes="[8, 16, 24, 32]"
        layout="total, sizes, prev, pager, next, jumper"
        :total="commentList.total"
      ></el-pagination>
    </el-card>
  </div>
</template>
<script>
export default {
  data() {
    return {
      commentList: {}, 
      queryInfo: { pagenum: 1, pagesize: 8, query: "" }, 
      replyDialogVisible: false,
      editForm: {},
      replyForm: {},
      statusQuery:0,
    };
  },
  created() {
       this.$emit('changeMenu',this.$route.path)
    this.$myLoading();
    this.getCommentList();

  },
  methods: {
    async getCommentList() {
      const res = await this.$http.get("/comments", {
        params: this.queryInfo
      });
      if (res.meta.status == 400)
        return this.$message.error("获取文章评论失败");
      this.commentList = res.data;
    },
    //页码切换
    handleCurrentChange(newpage) {
      this.queryInfo.pagenum = newpage;
      this.getCommentList();
    },
    //页面大小
    handleSizeChange(newsize) {
      this.queryInfo.pagesize = newsize;
      this.getCommentList();
    },
    async stateChange(cid) {
      let res = await this.$http.put(`comments/${cid}/status`);
      if (res.meta.status != 200) {
        return this.$message.error("审批失败");
      }
      this.$message.success("已审批");
      this.getCommentList();
    },
    //状态筛选
    handleStatusQuery(){
      this.queryInfo.status=this.statusQuery;
      this.getCommentList()
    },
    addComment() {
      this.$router.push("/Comment/add");
    },

    async deleteComment(id) {
      const confirm = await this.$confirm("是否删除该评论?", "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning"
      }).catch(err => err);
      if (confirm == "confirm") {
        let res = await this.$http.delete(`comments/${id}`);
        if (res.meta.status != 200)
          this.$message.error("删除评论失败" + res.meta.msg);
        else this.$message.success(res.meta.msg);
        this.getCommentList();
      } else this.$message.error("取消删除");
    },
    handleReplyClose() {
      this.replyDialogVisible = false;
      this.replyForm = {};
    },
    async handleReply() {
      let aid = this.replyForm.aid;
      let form = {
        content: this.replyForm.content,
        qq: "2522134117",
        nickname: "JackWang",
        cid: this.replyForm.cid
      };
      let res = await this.$http.post("/comments/" + aid,form);
      if (res.meta.status != 200) return this.$message.error(res.meta.msg);
      this.$message.success("回复成功");
      this.getCommentList();
      this.handleReplyClose();
    },
    async showReplyDialog(cid, aid) {
      this.replyDialogVisible = true;
      this.replyForm = {
        cid,
        aid
      };
    }
  }
};
</script>
<style  scoped>
.statusBox{
  display: flex;
  justify-content: space-between;
  width: 400px;
  align-items: center;
}
.searchBox{
  margin-top: 15px;
}
.addUser {
  margin-left: 15px;
}
.el-form {
  margin: 0 auto;
}
.search {
  width: 400px;
}
.el-dialog .el-form-item:last-child {
  margin-left: 80px;
}
.clickStatus:hover {
  cursor: pointer;
}

</style>