<template>
  <div>
    <el-breadcrumb separator-class="el-icon-arrow-right">
      <el-breadcrumb-item :to="{ path: '/index' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>实验室</el-breadcrumb-item>
    </el-breadcrumb>
    <el-card class="box-card">
      <div class="card-header">
        <!-- 搜索 -->
        <el-input
          placeholder="请输入内容"
          class="input-with-select search"
          v-model="queryInfo.query"
          clearable
          @clear="getProjectList"
        >
          <el-button
            slot="append"
            icon="el-icon-search"
            @click="queryInfo.pagenum=1;getProjectList()"
          ></el-button>
        </el-input>
        <el-button type="primary" class="addUser" @click="showAddDialog">添加项目</el-button>
      </div>
      <!--数据区-->
      <div class="card-main">
        <el-table :data="projects.projects" border style="width: 100%">
          <el-table-column type="index" label="#" width="50"></el-table-column>
          <el-table-column prop="name" label="项目名称" width="240"></el-table-column>
          <el-table-column prop="cover" label="封面" width="80" class="cover">
            <template slot-scope="scope">
              <el-avatar shape="square" :size="50" fit="fill" :src="url+scope.row.cover"></el-avatar>
            </template>
          </el-table-column>

          <el-table-column prop="intro" label="简介" width="400"></el-table-column>
          <el-table-column prop="address" label="文件路径" width="180"></el-table-column>
          <el-table-column prop="time" width="300" label="创建时间">
            <template slot-scope="scope">{{scope.row.time | dateFormat}}</template>
          </el-table-column>
          <el-table-column prop="caozuo" label="操作">
            <template slot-scope="scope">
              <el-tooltip class="item" effect="dark" content="编辑" placement="top">
                <el-button
                  type="primary"
                  size="mini"
                  icon="el-icon-edit"
                  @click="showEditDialog(scope.row)"
                ></el-button>
              </el-tooltip>
              <el-tooltip class="item" effect="dark" content="删除" placement="top">
                <el-button
                  type="danger"
                  size="mini"
                  icon="el-icon-delete"
                  @click="deleteProject(scope.row._id)"
                ></el-button>
              </el-tooltip>
            </template>
          </el-table-column>
        </el-table>
      </div>
      <!--添加对话框-->
      <el-dialog title="添加项目" :visible.sync="addDialogVisible" width="40%" @close="handleAddClose">
        <el-form :model="addForm" ref="addFormRef" :rules="Rules" label-width="80px">
          <el-form-item label="项目名称" prop="name">
            <el-input v-model="addForm.name"></el-input>
          </el-form-item>
            <el-form-item label="路径地址" prop="address">
            <el-input v-model="addForm.address" placeholder="/laboratory/"></el-input>
          </el-form-item>
          <el-form-item label="封面" required>
            <el-upload
              ref="addupload"
              class="upload-demo"
              :action="url+'/upload/cover'"
              list-type="picture"
              name="cover"
              :multiple="false"
              :limit="1"
              :on-success="handleAddCoverUpload"
            >
              <el-button size="small" type="primary">点击上传</el-button>
              <div slot="tip" class="el-upload__tip">只能上传jpg/png文件，且不超过500kb</div>
            </el-upload>
          </el-form-item>
          <el-form-item label="项目简介">
            <el-input type="textarea" :rows="2" placeholder="请输入内容" v-model="addForm.intro"></el-input>
          </el-form-item>
          <div class="el-form-item">
            <el-button @click="handleAddClose">取 消</el-button>
            <el-button type="primary" @click="addProject">确 定</el-button>
          </div>
        </el-form>
      </el-dialog>
      <!--编辑对话框-->
      <el-dialog
        title="编辑分类"
        :visible.sync="editDialogVisible"
        width="40%"
        @close="handleEditClose"
      >
        <el-form :model="editForm" ref="editFormRef" :rules="Rules" label-width="80px">
          <el-form-item label="项目名称" prop="name">
            <el-input v-model="editForm.name"></el-input>
          </el-form-item>
          <el-form-item label="路径地址" prop="address">
            <el-input v-model="editForm.address"></el-input>
          </el-form-item>
          <el-form-item label="封面" required>
            <el-upload
              ref="editupload"
              class="upload-demo"
              :action="url+'/upload/cover'"
              list-type="picture"
              name="cover"
              :multiple="false"
              :limit="1"
              :file-list="file"
              :on-remove="handleRemoveCover"
              :on-success="handleEditCoverUpload"
            >
              <el-button size="small" type="primary">点击上传</el-button>
              <div slot="tip" class="el-upload__tip">只能上传jpg/png文件，且不超过500kb</div>
            </el-upload>
          </el-form-item>
          <el-form-item label="项目简介">
            <el-input type="textarea" :rows="2" placeholder="请输入内容" v-model="editForm.intro"></el-input>
          </el-form-item>
          <div class="el-form-item">
            <el-button @click="handleEditClose">取 消</el-button>
            <el-button type="primary" @click="editProject">确 定</el-button>
          </div>
        </el-form>
      </el-dialog>
      <!--分页-->
      <el-pagination
        @current-change="handleCurrentChange"
        :current-page="queryInfo.pagenum"
        :page-size="queryInfo.pagesize"
        layout="total, prev, pager, next, jumper"
        :total="projects.total"
      ></el-pagination>
    </el-card>
  </div>
</template>
<script>
export default {
  data() {
    return {
      url: "",
      projects: {}, 
      queryInfo: { pagenum: 1, pagesize: 7, query: "" }, //请求信息
      addDialogVisible: false,
      editDialogVisible: false,
      addForm: {},
      editForm: {},
      Rules: {
        name: {
          required: true,
          message: "请输入项目名称",
          trigger: "blur"
        },
        address: {
          required: true,
          message: "请输入文件路径",
          trigger: "blur"
        }
      },
      file: []
    };
  },
  created() {
    this.$emit("changeMenu", this.$route.path);
    this.$myLoading();
    this.url = this.$serveUrl;
    this.getProjectList();
  },
  methods: {
    async getProjectList() {
      const res = await this.$http.get("/laboratory", {
        params: this.queryInfo
      });
      if (res.meta.status != 200)
        return this.$message.error("获取数据列表失败");
      this.projects = res.data;
    },
    //页码切换
    handleCurrentChange(newpage) {
      this.queryInfo.pagenum = newpage;
      this.getProjectList();
    },
    //页面大小

    handleAddCoverUpload(res, file, fileList) {
      this.addForm.cover = res.data.url;
    },
    handleEditCoverUpload(res, file, fileList) {
      this.editForm.cover = res.data.url;
    },
    addProject() {
      var that = this;
      this.$refs.addFormRef.validate(async valid => {
        if (valid) {
          if (!that.addForm.cover) return that.$message.error("请选择封面");
          that.addForm.time = new Date();
          let res = await that.$http.post(`laboratory`, that.addForm);
          that.handleAddClose();
          if (res.meta.status != 200) that.$message.error("添加失败");
          else {
            that.$message.success("添加成功");
            that.getProjectList();
          }
        }
      });
    },
    editProject() {
      var that = this;
      this.$refs.editFormRef.validate(async valid => {
        if (valid) {
          if (!that.editForm.cover) return that.$message.error("请选择封面");
          let res = null;
          //修改过封面
          res = await that.$http.put(`laboratory/${that.editForm._id}`, {
            name: that.editForm.name,
            cover:  that.editForm.cover ,
            intro: that.editForm.intro,
            address:that.editForm.address
          });
          that.handleEditClose();
          if (res.meta.status != 200) that.$message.error("修改失败");
          else {
            that.$message.success("修改成功");
            that.getProjectList();
          }
        }
      });
    },
    async deleteProject(id) {
      const confirm = await this.$confirm("是否删除该项目?", "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning"
      }).catch(err => err);
      if (confirm == "confirm") {
        let res = await this.$http.delete(`laboratory/${id}`);
        if (res.meta.status != 200)
          this.$message.error("删除失败" + res.meta.msg);
        else this.$message.success("删除成功");
        this.getProjectList();
      } else this.$message.error("取消删除");
    },
    handleEditClose() {
      this.file = [];
      this.editDialogVisible = false;
      this.fileChanged = false;
      this.editForm = {};
      this.$refs.editFormRef.resetFields();
    },
    handleAddClose() {
      this.addDialogVisible = false;
      this.addForm = {};
      this.$refs.addupload.clearFiles();
      this.$refs.addFormRef.resetFields();
    },
    handleRemoveCover() {
      this.fileChanged = true;
      this.editForm.cover = null;
    },
    showAddDialog() {
      this.addDialogVisible = true;
    },
    showEditDialog(proInfo) {
      let row = JSON.parse(JSON.stringify(proInfo));
      this.fileChanged = false;
      this.file.push({
        name: "封面",
        url: "http://localhost:80" + row.cover
      });
      this.editDialogVisible = true;
      this.editForm = row;
    }
  }
};
</script>
<style  scoped>
.addUser {
  margin-left: 15px;
}
.el-form {
  margin: 0 auto;
}
.search {
  width: 500px;
}
.el-dialog .el-form-item:last-child {
  margin-left: 80px;
}
</style>