<template>
  <div>
    <el-breadcrumb separator-class="el-icon-arrow-right">
      <el-breadcrumb-item :to="{ path: '/index' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>用户管理</el-breadcrumb-item>
      <el-breadcrumb-item>用户列表</el-breadcrumb-item>
    </el-breadcrumb>
    <el-card class="box-card">
      <div class="card-header">
        <!-- 搜索 -->
        <el-input
          placeholder="请输入内容"
          class="input-with-select search"
          v-model="queryInfo.query"
          clearable
          @clear="getUserList"
        >
          <el-button slot="append" icon="el-icon-search" @click="queryInfo.pagenum=1;getUserList()"></el-button>
        </el-input>
      </div>
      <!--数据区-->
      <div class="card-main">
        <el-table :data="userList.users" border style="width: 100%">
          <el-table-column type="index" label="#" width="50"></el-table-column>
          <el-table-column prop="username" label="用户名" width="180"></el-table-column>
          <el-table-column prop="qq" label="QQ" width="180"></el-table-column>
          <el-table-column prop="role" label="角色">
            <template slot-scope="scope">{{scope.row.role=='admin'?'管理员':'普通'}}</template>
          </el-table-column>
          <el-table-column prop="state" label="状态">
            <template slot-scope="scope">
              <el-switch
                v-model="scope.row.state"
                active-color="#13ce66"
                inactive-color="#ff4949"
                :active-value="1"
                :inactive-value="0"
                @change="stateChange(scope.row)"
              ></el-switch>
            </template>
          </el-table-column>
          <el-table-column prop="caozuo" label="操作">
            <template slot-scope="scope">
              <el-tooltip class="item" effect="dark" content="编辑" placement="top">
                <el-button
                  type="primary"
                  size="mini"
                  icon="el-icon-edit"
                  @click="showEditDialog(scope.row)"
                ></el-button>
              </el-tooltip>
              <el-tooltip class="item" effect="dark" content="删除" placement="top">
                <el-button
                  type="danger"
                  size="mini"
                  icon="el-icon-delete"
                  @click="deleteUser(scope.row._id)"
                ></el-button>
              </el-tooltip>
            </template>
          </el-table-column>
        </el-table>
      </div>
      <!--编辑对话框-->
      <el-dialog
        title="编辑用户"
        :visible.sync="editDialogVisible"
        width="40%"
        @close="handleEditClose"
      >
        <el-form :model="editForm" ref="editFormRef" :rules="editRules" label-width="80px">
          <el-form-item label="QQ" prop="qq">
            <el-input v-model="editForm.qq" ></el-input>
          </el-form-item>
          <el-form-item label="用户名" prop="username">
            <el-input v-model="editForm.username"></el-input>
          </el-form-item>
          <el-form-item label="角色">
            <el-select v-model="editForm.role" placeholder="请选择">
              <el-option
                v-for="item in [
                    {value:'normal',label:'普通'},
                    {value:'admin',label:'管理员'}
                ]"
                :key="item.value"
                :label="item.label"
                :value="item.value"
              ></el-option>
            </el-select>
          </el-form-item>
          <div class="el-form-item">
            <el-button @click="handleEditClose">取 消</el-button>
            <el-button type="primary" @click="editUser">确 定</el-button>
          </div>
        </el-form>
      </el-dialog>
      <!--分页-->
      <el-pagination
        @current-change="handleCurrentChange"
        :current-page="queryInfo.pagenum"
        :page-size="queryInfo.pagesize"
        layout="total, prev, pager, next, jumper"
        :total="userList.total"
      ></el-pagination>
    </el-card>
  </div>
</template>
<script>
export default {
  data() {
    return {
      userList: {}, //用户列表
      queryInfo: { pagenum: 1, pagesize: 6, query: "" }, //请求信息
      editDialogVisible: false,
      editForm: {},
      editRules: {
        qq: {
          required: true,
          message: "请输入QQ号",
          trigger: "blur"
        },
        username: {
          required: true,
          min: 1,
          max: 16,
          message: "请输入用户名",
          trigger: "blur"
        }
      }
    };
  },
  created() {
       this.$emit('changeMenu',this.$route.path)
    this.$myLoading();
    this.getUserList();
  },
  methods: {
    //获取用户列表
    async getUserList() {
      const users = await this.$http.get("/users", {
        params: this.queryInfo
      });
      if (users.meta.status == 400)
        return this.$message.error("获取用户列表失败");
      this.userList = users.data;
    },
    //页码切换
    handleCurrentChange(newsize) {
      this.queryInfo.pagenum = newsize;
      this.getUserList();
    },
    //修改用户状态
    async stateChange(userInfo) {
      let res = await this.$http.put(
        `users/${userInfo._id}/state/${userInfo.state}`
      );
      if (res.meta.status != 200) {
        this.userList.users.state = !this.userList.users.state;
        return this.$message.error("修改状态失败");
      }
      this.$message.success("状态修改成功");
    },
    editUser() {
      var that = this;
      this.$refs.editFormRef.validate(async valid => {
        if (valid) {
          let res = await that.$http.put(`users/${that.editForm._id}`, {
            qq: that.editForm.qq,
            username: that.editForm.username,
            role:that.editForm.role
          });
          that.handleEditClose();
          if (res.meta.status != 200) that.$message.error("提交更改失败");
          else {
            that.$message.success("提交更改成功");
            that.getUserList();
          }
        }
      });
    },
    async deleteUser(id) {
      const confirm = await this.$confirm("是否删除该用户?", "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning"
      }).catch(err => err);
      if (confirm == "confirm") {
        let res = await this.$http.delete(`users/${id}`);
        if (res.meta.status != 200)
          this.$message.error("删除用户失败" + res.meta.msg);
        else this.$message.success("删除用户成功");
        this.getUserList();
      } else this.$message.error("取消删除");
    },
    handleEditClose() {
      this.editDialogVisible = false;
      this.editForm={}
      this.$refs.editFormRef.resetFields();
    },

    async showEditDialog(userInfo) {
      this.editDialogVisible = true;
      this.editForm = JSON.parse(JSON.stringify(userInfo));
    }
  }
};
</script>
<style  scoped>
.addUser {
  margin-left: 15px;
}
.el-form {
  margin: 0 auto;
}
.search {
  width: 500px;
}
.el-dialog .el-form-item:last-child {
  margin-left: 80px;
}
</style>