<template>
  <div>
    <el-breadcrumb separator-class="el-icon-arrow-right">
      <el-breadcrumb-item :to="{ path: '/index' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>文章管理</el-breadcrumb-item>
      <el-breadcrumb-item>文章列表</el-breadcrumb-item>
    </el-breadcrumb>
    <!--头部筛选卡片-->
    <el-card>
      <el-form label-width="130px" label-position="left">
        <div class="card-header">
          <el-form-item label="是否原创:">
            <el-select v-model="queryForm.original" placeholder="请选择">
              <el-option
                v-for="item in searchSelection.original"
                :key="item.value"
                :label="item.name"
                :value="item.value"
              ></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="是否公开">
            <el-select v-model="queryForm.public" placeholder="请选择">
              <el-option
                v-for="item in searchSelection.public"
                :key="item.value"
                :label="item.name"
                :value="item.value"
              ></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="所属分类">
            <el-select v-model="queryForm.category" placeholder="请选择">
              <el-option
                label="所有"
                value=""
              ></el-option>
              <el-option
                v-for="item in searchSelection.category"
                :key="item.cgid"
                :label="item.cgname"
                :value="item.cgid"
              ></el-option>
            </el-select>
          </el-form-item>
          <div style="margin-right:150px">
            <el-button type="primary" @click="handleQuery">查询</el-button>
          </div>
          <!-- 搜索 -->
          <div>
            <el-input
              placeholder="文章标题"
              class="input-with-select search"
              v-model="queryInfo.query"
              clearable
              @clear="getArticleList"
            >
              <el-button
                slot="append"
                icon="el-icon-search"
                @click="queryInfo.pagenum=1;getArticleList()"
              ></el-button>
            </el-input>
            <el-button type="primary" class="addUser" @click="addArticle">写文章</el-button>
          </div>
        </div>
      </el-form>
    </el-card>
    <el-card class="box-card">
      <!--数据区-->
      <div class="card-main">
        <el-table :data="articleList.articles" border style="width: 100%">
          <el-table-column type="index" label="#" width="50"></el-table-column>
          <el-table-column prop="title" label="标题" width="300"></el-table-column>
          <el-table-column prop="cover" label="封面" width="80" class="cover">
            <template slot-scope="scope">
              <el-avatar shape="square" :size="50" fit="fill" :src="url+scope.row.cover"></el-avatar>
            </template>
          </el-table-column>
          <el-table-column prop="pageviews" label="浏览" width="180"></el-table-column>
          <el-table-column prop="cgname" label="分类" width="180"></el-table-column>
          <el-table-column prop="public" label="公开/私密" width="120">
            <template slot-scope="scope">
              <el-switch
                v-model="scope.row.public"
                :active-value="1"
                :inactive-value="0"
                active-color="#13ce66"
                inactive-color="#ff4949"
                @change="togglePublic($event,scope.row._id)"
              ></el-switch>
            </template>
          </el-table-column>
          <el-table-column prop="openCmt" label="评论开启" width="120">
            <template slot-scope="scope">
              <el-switch
                v-model="scope.row.openCmt"
                :active-value="1"
                :inactive-value="0"
                active-color="#13ce66"
                inactive-color="#ff4949"
                @change="toggleCmt($event,scope.row._id)"
              ></el-switch>
            </template>
          </el-table-column>
          <el-table-column prop="publishDate" width="300" label="创建时间">
            <template slot-scope="scope">{{scope.row.publishDate | dateFormat}}</template>
          </el-table-column>
          <el-table-column prop="caozuo" label="操作">
            <template slot-scope="scope">
              <el-tooltip class="item" effect="dark" content="编辑" placement="top">
                <el-button
                  type="primary"
                  size="mini"
                  icon="el-icon-edit"
                  @click="editArticle(scope.row._id)"
                ></el-button>
              </el-tooltip>
              <el-tooltip class="item" effect="dark" content="删除" placement="top">
                <el-button
                  type="danger"
                  size="mini"
                  icon="el-icon-delete"
                  @click="deleteArticle(scope.row._id)"
                ></el-button>
              </el-tooltip>
            </template>
          </el-table-column>
        </el-table>
      </div>
      <!--编辑对话框-->
      <el-dialog
        title="编辑用户"
        :visible.sync="editDialogVisible"
        width="40%"
        @close="handleEditClose"
      >
        <el-form :model="editForm" ref="editFormRef" :rules="editRules" label-width="80px">
          <el-form-item label="QQ" prop="qq">
            <el-input v-model="editForm.qq"></el-input>
          </el-form-item>
          <el-form-item label="用户名" prop="username">
            <el-input v-model="editForm.username"></el-input>
          </el-form-item>
          <el-form-item label="角色">
            <el-select v-model="editForm.role" placeholder="请选择">
              <el-option
                v-for="item in [
                    {value:'normal',label:'普通'},
                    {value:'admin',label:'管理员'}
                ]"
                :key="item.value"
                :label="item.label"
                :value="item.value"
              ></el-option>
            </el-select>
          </el-form-item>
          <div class="el-form-item">
            <el-button @click="handleEditClose">取 消</el-button>
            <el-button type="primary" @click="editUser">确 定</el-button>
          </div>
        </el-form>
      </el-dialog>
      <!--分页-->
      <el-pagination
        @size-change="handleSizeChange"
        @current-change="handleCurrentChange"
        :current-page="queryInfo.pagenum"
        :page-size="queryInfo.pagesize"
        :page-sizes="[6, 10, 14, 18]"
        layout="total, sizes, prev, pager, next, jumper"
        :total="articleList.total"
      ></el-pagination>
    </el-card>
  </div>
</template>
<script>
export default {
  props: [],
  data() {
    return {
      url: "",
      articleList: {}, //用户列表
      queryInfo: { pagenum: 1, pagesize: 6, query: "" }, //请求信息
      //查询选项
      searchSelection: {
        original: [
          { name: "原创", value: 1 },
          { name: "转载", value: 0 }
        ],
        public: [
          { name: "公开", value: 1 },
          { name: "私人", value: 0 }
        ],
        category: []
      },
      queryForm: {
        public: 1,
        original: 1,
        category: 0
      },
      editDialogVisible: false,
      editForm: {},
      editRules: {
        qq: {
          required: true,
          message: "请输入QQ号",
          trigger: "blur"
        },
        username: {
          required: true,
          min: 1,
          max: 16,
          message: "请输入用户名",
          trigger: "blur"
        }
      }
    };
  },
  created() {
    this.$myLoading();
   this.$emit('changeMenu',this.$route.path)
    this.url = this.$serveUrl;
    this.getArticleList();
    this.getCategoryList();
  },
  methods: {
    async getArticleList() {
      const res = await this.$http.get("/articles", {
        params: this.queryInfo
      });
      if (res.meta.status == 400)
        return this.$message.error("获取文章列表失败");
      this.articleList = res.data;
    },
    async getCategoryList() {
      const res = await this.$http.get("/categories/list");
      if (res.meta.status != 200)
        return this.$message.error("获取分类列表失败");
      this.searchSelection.category = res.data;
    },
    //页码切换
    handleCurrentChange(newpage) {
      this.queryInfo.pagenum = newpage;
      this.getArticleList();
    },
    //页面大小
    handleSizeChange(newsize) {
      this.queryInfo.pagesize = newsize;
      this.getArticleList();
    },

    addArticle() {
      this.$emit("changeMenu", "/article/add");
    },
    editArticle(id) {
      this.$emit("changeMenu", "/article/add",id);
    },
    editUser() {
      var that = this;
      this.$refs.editFormRef.validate(async valid => {
        if (valid) {
          let res = await that.$http.put(`users/${that.editForm._id}`, {
            qq: that.editForm.qq,
            username: that.editForm.username,
            role: that.editForm.role
          });
          that.handleEditClose();
          if (res.meta.status != 200) that.$message.error("提交更改失败");
          else {
            that.$message.success("提交更改成功");
            that.getArticleList();
          }
        }
      });
    },
    async deleteArticle(id) {
      const confirm = await this.$confirm("是否删除该文章?", "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning"
      }).catch(err => err);
      if (confirm == "confirm") {
        let res = await this.$http.delete(`articles/${id}`);
        if (res.meta.status != 200)
          this.$message.error("删除文章失败" + res.meta.msg);
        else this.$message.success("删除文章成功");
        this.getArticleList();
      } else this.$message.error("取消删除");
    },
    handleEditClose() {
      this.editDialogVisible = false;
      this.editForm = {};
      this.$refs.editFormRef.resetFields();
    },
    //公开状态变更
    async togglePublic(e, id) {
      let result = await this.$http.put("/articles/" + id, { public: e });
      if (result.meta.status != 200) {
        this.$message.error("修改失败");
        this.getArticleList();
      } else {
        if (e == 1) this.$message.success("已变更为公开");
        else this.$message.warning("已变更为私密");
      }
    },
    async toggleCmt(e, id) {
      let result = await this.$http.put("/articles/" + id, { openCmt: e });
      if (result.meta.status != 200) {
        this.$message.error("修改失败");
        this.getArticleList();
      } else {
        if (e == 1) this.$message.success("已开启评论");
        else this.$message.warning("已关闭评论");
      }
    },
    async handleQuery() {
      let that = this;
      let newQueryInfo = {
        ...that.queryInfo,
        ...that.queryForm
      };
      let result = await this.$http.get("/articles", {
        params: newQueryInfo
      });
      if (result.meta.status != 200) return this.$message.error("查询失败");
      this.articleList = result.data;
    }
  }
};
</script>
<style  scoped>
.addUser {
  margin-left: 15px;
}
.el-form {
  margin: 0 auto;
}
.search {
  width: 350px;
}
.card-header {
  display: flex;
  justify-content: space-between;
  flex-wrap: wrap;
}
.el-dialog .el-form-item:last-child {
  margin-left: 80px;
}
</style>