<template>
  <div>
    <el-breadcrumb separator-class="el-icon-arrow-right">
      <el-breadcrumb-item :to="{ path: '/index' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>系统设置</el-breadcrumb-item>
      <el-breadcrumb-item>网站管理</el-breadcrumb-item>
    </el-breadcrumb>
    <el-card class="box-card">
      <el-tabs v-model="activeName">
        <el-tab-pane label="基本设置" name="1">
          <el-form label-position="left" label-width="300px">
            <el-form-item label="网站域名" required>
              <el-input v-model="form1.domainName"></el-input>
            </el-form-item>
            <el-form-item label="网站名称" required>
              <el-input v-model="form1.sitename"></el-input>
            </el-form-item>
            <el-form-item label="网站图标" required>
              <el-upload
                ref="editupload"
                class="upload-demo"
                :action="url+'/upload/img'"
                list-type="picture"
                name="img"
                :multiple="false"
                :limit="1"
                :file-list="file_favicon"
                :on-remove="handleRemoveFavicon"
                :on-success="handleUploadFavicon"
              >
                <el-button size="small" type="primary">点击上传</el-button>
                <div slot="tip" class="el-upload__tip">只能上传ico文件，且不超过500kb</div>
              </el-upload>
            </el-form-item>
            <el-divider></el-divider>
            <el-form-item label="网站关键字">
              <el-input type="textarea" v-model="form1.keywords"></el-input>
            </el-form-item>
            <el-form-item label="网站描述">
              <el-input type="textarea" v-model="form1.intro"></el-input>
            </el-form-item>
            <el-button type="primary" @click="saveForm1">保存</el-button>
          </el-form>
        </el-tab-pane>
        <el-tab-pane label="其他设置" name="2">
          <el-form v-model="form2" label-width="300px" label-position="left">
            <el-form-item label="文章评论" required>
              <el-radio v-model="form2.openCmt" :label="1">开启</el-radio>
              <el-radio v-model="form2.openCmt" :label="0">关闭</el-radio>
            </el-form-item>
            <el-form-item label="评论审批" required>
              <el-radio v-model="form2.approvalCmt" :label="1">开启</el-radio>
              <el-radio v-model="form2.approvalCmt" :label="0">关闭</el-radio>
            </el-form-item>
            <el-form-item label="主页背景" required>
              <el-upload
                ref="editupload"
                class="upload-demo"
                :action="url+'/upload/img'"
                list-type="picture"
                name="img"
                :multiple="false"
                :limit="1"
                :file-list="file_bg"
                :on-remove="handleRemoveBg"
                :on-success="handleUploadBg"
              >
                <el-button size="small" type="primary">点击上传</el-button>
                <div slot="tip" class="el-upload__tip">只能上传jpg/png文件，且不超过500kb</div>
              </el-upload>
            </el-form-item>
            <el-form-item label="启动日期" required>
              <el-date-picker type="datetime" v-model="form2.startDate" placeholder="选择日期时间"></el-date-picker>
            </el-form-item>
            <el-button type="primary" @click="saveForm2">保存</el-button>
          </el-form>
        </el-tab-pane>
      </el-tabs>
    </el-card>
  </div>
</template>
<script>
export default {
  data() {
    return {
      url:'',
      form1: {},
      form2: {},
      file_favicon: [],
      file_bg: [],
      activeName: "1"
    };
  },
  created() {
       this.$emit('changeMenu',this.$route.path)
    this.$myLoading();
    this.url=this.$serveUrl
    this.getSettings();
  },
  methods: {
    async getSettings() {
      let result = await this.$http.get("/setting");
      let setting = result.data;
      this.form1 = {
        domainName: setting.domainName,
        sitename: setting.sitename,
        favicon: setting.favicon,
        keywords: setting.keywords,
        intro: setting.intro
      };
      this.form2 = {
        openCmt: setting.openCmt,
        approvalCmt: setting.approvalCmt,
        bg: setting.bg,
        startDate: setting.startDate
      };
        this.file_favicon = [];
        this.file_favicon.push({
          name: "网站图标",
          url: setting.domainName + setting.favicon
        });   
        this.file_bg = [];
        this.file_bg.push({
          name: "主页背景",
          url: setting.domainName + setting.bg
        });
      
    },
    handleRemoveFavicon() {
      this.form1.favicon = null;
    },
    handleUploadFavicon(res, file, fileList) {
      this.form1.favicon = res.data.url;
    },
    handleRemoveBg() {
      this.form2.bg = null;
    },
    handleUploadBg(res, file, fileList) {
      this.form2.bg = res.data.url;
    },
    async saveForm1() {
      let result = await this.$http.put("/setting", this.form1);
      if (result.meta.status != 200) return this.$message.error("保存失败");
      this.$message.success("保存成功");
      this.getSettings();
    },
    async saveForm2() {
      let result = await this.$http.put("/setting", this.form2);
      if (result.meta.status != 200) return this.$message.error("保存失败");
      this.$message.success("保存成功");
      this.getSettings();
    }
  }
};
</script>
<style  scoped>
.el-form {
  width: 60%;
}
</style>