<template>
  <div>
    <el-breadcrumb separator-class="el-icon-arrow-right">
      <el-breadcrumb-item :to="{ path: '/index' }">首页</el-breadcrumb-item>
    </el-breadcrumb>
    <div class="card-info">
      <el-card class="info-item">
        <div slot="header">
          <span>网站访问</span>
        </div>
        <div class="numInfo">
          <span class="num">{{blogInfo.visitors}}</span>
          <span>次</span>
        </div>
      </el-card>
      <el-card class="info-item">
        <div slot="header">
          <span>建站天数</span>
        </div>
        <div class="numInfo">
          <span class="num">{{blogInfo.runtime}}</span>
          <span>天</span>
        </div>
      </el-card>
      <el-card class="info-item">
        <div slot="header">
          <span>文章数量</span>
        </div>
        <div class="numInfo">
          <span class="num">{{blogInfo.articleCount}}</span>
          <span>篇</span>
        </div>
      </el-card>
      <el-card class="info-item">
        <div slot="header">
          <span>评论数量</span>
        </div>
        <div class="numInfo">
          <span class="num">{{blogInfo.commentCount}}</span>
          <span>个</span>
        </div>
      </el-card>
    </div>
    <el-card>
      <div class="card-charts">
        <div class="chart" ref="chart1">1</div>
        <div class="chart" ref="chart2">2</div>
      </div>
    </el-card>
  </div>
</template>
<script>
export default {
  data() {
    return {
      blogInfo: {}
    };
  },
  created() {
    this.$emit('changeMenu',this.$route.path)
    this.$myLoading();
    this.getBlogInfo();
    this.getReports();
  },
  methods: {
    async getReports() {
      let that = this;
      let result = await this.$http.get("/reports");
      let { categoryGroup, pageviewGroup, commentGroup } = result.data;
      let pgvObj = {
        x: [],
        y: []
      };
      pageviewGroup.forEach(item => {
        pgvObj.x.push(item.title);
        pgvObj.y.push(item.pageviews);
      });

      let option1 = {
        title: {
          text: "文章访客"
        },
        grid: {
          left: "9%",
          bottom: "1%",
          right: "5%",
          //显示刻度标签
          containLabel: true,
          //显示边框
          show: true,
          borderColor: "#012f4a"
        },
        xAxis: {
          type: "category",
          boundaryGap: false,
          data: pgvObj.x,
          axisLabel: {
            interval: 0,
            rotate: 40
          }
        },
        yAxis: {
          type: "value",
          //y轴分割线
          splitLine: {
            lineStyle: {
              color: "rgba(255,255,255,.1)"
            }
          }
        },
        series: {
          name: "销量",
          type: "bar",
          //数据堆叠
          stack: "总量",
          barWidth: "20%",
          //折现平滑显示
          smooth: true,
          data: pgvObj.y
        },
        color: ["#3bbdda"]
      };
      let option2 = {
        title: {
          text: "文章分类"
        },
        tooltip: {
            trigger: 'item',
            formatter: '{a} <br/>{b} : {c} ({d}%)'
        },
        legend: {
            left: 'center',
            bottom: 0,
            itemHeight: 10,
            itemWidth: 10,
            textStyle: {
                color: 'rgb(0,0,0)'
            }
        }, series: {
            name: '文章数量',
            type: 'pie',
            radius: [50, 170],
            center: ['50%', '50%'],
            roseType: 'radius',
            label: {
                fontSize: 25,

            },
            emphasis: {
                label: {
                    show: true
                }
            },
            data:categoryGroup
        },
        color: ['#006cff', '#60cda0', '#ed8884', '#ff9f7f', '#0096ff', '#9fe6b8', '#32c5e9', '#1d9dff']
      };
      this.$nextTick(() => {
        let chart1 = this.$echarts.init(this.$refs.chart1);
        let chart2 = this.$echarts.init(this.$refs.chart2);
        chart1.setOption(option1);
        chart2.setOption(option2);
      });
    },
    async getBlogInfo() {
      let result = await this.$http.get("/bloginfo");
      this.blogInfo = result.data;
    }
  }
};
</script>
<style  scoped>
.card-info {
  display: flex;
  justify-content: space-between;
  align-items: center;
  width: 100%;
}
.numInfo {
  text-align: center;
}
.num {
  font-family: numFont;
  font-size: 40px;
}
.info-item {
  width: 400px;
  height: 150px;
}
.chart {
  width: 45%;
height: 600px;
  margin-bottom: 15px;
}
.card-charts {
  display: flex;
  justify-content: space-around;
  flex-wrap: wrap;
}
</style>