<template>
  <div>
    <el-breadcrumb separator-class="el-icon-arrow-right">
      <el-breadcrumb-item :to="{ path: '/index' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>文章管理</el-breadcrumb-item>
      <el-breadcrumb-item>文章列表</el-breadcrumb-item>
    </el-breadcrumb>
    <el-card class="box-card">
      <div class="card-header">
        <!-- 搜索 -->
        <el-input
          placeholder="请输入内容"
          class="input-with-select search"
          v-model="queryInfo.query"
          clearable
          @clear="getCategoryList"
        >
          <el-button
            slot="append"
            icon="el-icon-search"
            @click="queryInfo.pagenum=1;getCategoryList()"
          ></el-button>
        </el-input>
        <el-button type="primary" class="addUser" @click="showAddDialog">添加分类</el-button>
      </div>
      <!--数据区-->
      <div class="card-main">
        <el-table :data="categoryList.categories" border style="width: 100%">
          <el-table-column type="index" label="#" width="50"></el-table-column>
          <el-table-column prop="cgname" label="分类名称" width="240"></el-table-column>
          <el-table-column prop="cover" label="封面" width="80" class="cover">
            <template slot-scope="scope">
              <el-avatar
                shape="square"
                :size="50"
                fit="fill"
                :src="url+scope.row.cover"
              ></el-avatar>
            </template>
          </el-table-column>

          <el-table-column prop="intro" label="简介" width="400"></el-table-column>
          <el-table-column prop="count" label="文章数" width="180"></el-table-column>
          <el-table-column prop="createtime" width="300" label="创建时间">
            <template slot-scope="scope">{{scope.row.createtime | dateFormat}}</template>
          </el-table-column>
          <el-table-column prop="caozuo" label="操作">
            <template slot-scope="scope">
              <el-tooltip class="item" effect="dark" content="编辑" placement="top">
                <el-button
                  type="primary"
                  size="mini"
                  icon="el-icon-edit"
                  @click="showEditDialog(scope.row)"
                ></el-button>
              </el-tooltip>
              <el-tooltip class="item" effect="dark" content="删除" placement="top">
                <el-button
                  type="danger"
                  size="mini"
                  icon="el-icon-delete"
                  @click="deleteCategory(scope.row.cgid)"
                ></el-button>
              </el-tooltip>
            </template>
          </el-table-column>
        </el-table>
      </div>
      <!--添加对话框-->
      <el-dialog title="添加分类" :visible.sync="addDialogVisible" width="40%" @close="handleAddClose">
        <el-form :model="addForm" ref="addFormRef" :rules="Rules" label-width="80px">
          <el-form-item label="分类名称" prop="cgname">
            <el-input v-model="addForm.cgname"></el-input>
          </el-form-item>
          <el-form-item label="分类封面" required>
            <el-upload
              ref="addupload"
              class="upload-demo"
              :action="url+'/upload/cover'"
              list-type="picture"
              name="cover"
              :multiple="false"
              :limit="1"
              :on-success="handleAddCoverUpload"
            >
              <el-button size="small" type="primary">点击上传</el-button>
              <div slot="tip" class="el-upload__tip">只能上传jpg/png文件，且不超过500kb</div>
            </el-upload>
          </el-form-item>
          <el-form-item label="分类简介">
            <el-input type="textarea" :rows="2" placeholder="请输入内容" v-model="addForm.intro"></el-input>
          </el-form-item>
          <div class="el-form-item">
            <el-button @click="handleAddClose">取 消</el-button>
            <el-button type="primary" @click="addCategory">确 定</el-button>
          </div>
        </el-form>
      </el-dialog>
      <!--编辑对话框-->
      <el-dialog
        title="编辑分类"
        :visible.sync="editDialogVisible"
        width="40%"
        @close="handleEditClose"
      >
        <el-form :model="editForm" ref="editFormRef" :rules="Rules" label-width="80px">
          <el-form-item label="分类名称" prop="cgname">
            <el-input v-model="editForm.cgname"></el-input>
          </el-form-item>
          <el-form-item label="分类封面" required>
            <el-upload
              ref="editupload"
              class="upload-demo"
              :action="url+'/upload/cover'"
              list-type="picture"
              name="cover"
              :multiple="false"
              :limit="1"
              :file-list="file"
              :on-remove="handleRemoveCover"
              :on-success="handleEditCoverUpload"
            >
              <el-button size="small" type="primary">点击上传</el-button>
              <div slot="tip" class="el-upload__tip">只能上传jpg/png文件，且不超过500kb</div>
            </el-upload>
          </el-form-item>
          <el-form-item label="分类简介">
            <el-input type="textarea" :rows="2" placeholder="请输入内容" v-model="editForm.intro"></el-input>
          </el-form-item>
          <div class="el-form-item">
            <el-button @click="handleEditClose">取 消</el-button>
            <el-button type="primary" @click="editCategory">确 定</el-button>
          </div>
        </el-form>
      </el-dialog>
      <!--分页-->
      <el-pagination
        @size-change="handleSizeChange"
        @current-change="handleCurrentChange"
        :current-page="queryInfo.pagenum"
        :page-size="queryInfo.pagesize"
        layout="total, prev, pager, next, jumper"
        :total="categoryList.total"
      ></el-pagination>
    </el-card>
  </div>
</template>
<script>
export default {
  data() {
    return {
      url:'',
      categoryList: {}, 
      queryInfo: { pagenum: 1, pagesize: 7, query: "" }, //请求信息
      addDialogVisible: false,
      editDialogVisible: false,
      addForm: {},
      editForm: {},
      Rules: {
        cgname: {
          required: true,
          message: "请输入分类名称",
          trigger: "blur"
        }
      },
      file: [],
      fileChanged: false
    };
  },
  created() {
       this.$emit('changeMenu',this.$route.path)
    this.$myLoading();
    this.url=this.$serveUrl
    this.getCategoryList();
  },
  methods: {
    async getCategoryList() {
      const res = await this.$http.get("/categories", {
        params: this.queryInfo
      });
      if (res.meta.status != 200)
        return this.$message.error("获取分类列表失败");
      this.categoryList = res.data;
    },
    //页码切换
    handleCurrentChange(newpage) {
      this.queryInfo.pagenum = newpage;
      this.getCategoryList();
    },
    //页面大小
    handleSizeChange(newsize) {
      this.queryInfo.pagesize = newsize;
      this.getCategoryList();
    },
    handleAddCoverUpload(res, file, fileList) {
      this.addForm.cover = res.data.url;
    },
    handleEditCoverUpload(res, file, fileList) {
      this.editForm.cover = res.data.url;
    },
    addCategory() {
      var that = this;
      this.$refs.addFormRef.validate(async valid => {
        if (valid) {
          if (!that.addForm.cover) return that.$message.error("请选择封面");
          that.addForm.createtime = new Date();
          let res = await that.$http.post(`categories`, that.addForm);
          that.handleAddClose();
          if (res.meta.status != 200) that.$message.error("创建分类失败");
          else {
            that.$message.success("创建分类成功");
            that.getCategoryList();
          }
        }
      });
    },
    editCategory() {
      var that = this;
      this.$refs.editFormRef.validate(async valid => {
        if (valid) {
          if (!that.editForm.cover) return that.$message.error("请选择封面");
          let res = null;
          //修改过封面
          res = await that.$http.put(`categories/${that.editForm.cgid}`, {
            cgname: that.editForm.cgname,
            cover: that.fileChanged ? that.editForm.cover : null,
            intro: that.editForm.intro
          });
          that.handleEditClose();
          if (res.meta.status != 200) that.$message.error("修改分类失败");
          else {
            that.$message.success("修改分类成功");
            that.getCategoryList();
          }
        }
      });
    },
    async deleteCategory(id) {
      const confirm = await this.$confirm("是否删除该分类?", "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning"
      }).catch(err => err);
      if (confirm == "confirm") {
        let res = await this.$http.delete(`categories/${id}`);
        if (res.meta.status != 200)
          this.$message.error("删除分类失败" + res.meta.msg);
        else this.$message.success("删除分类成功");
        this.getCategoryList();
      } else this.$message.error("取消删除");
    },
    handleEditClose() {
      this.file = [];
      this.editDialogVisible = false;
      this.fileChanged = false;
      this.editForm = {};
      this.$refs.editFormRef.resetFields();
    },
    handleAddClose() {
      this.addDialogVisible = false;
      this.addForm = {};
      this.$refs.addupload.clearFiles();
      this.$refs.addFormRef.resetFields();
    },
    handleRemoveCover() {
      this.fileChanged = true;
      this.editForm.cover = null;
    },
    showAddDialog() {
      this.addDialogVisible = true;
    },
    showEditDialog(cgInfo) {
      let cgrow = JSON.parse(JSON.stringify(cgInfo));
      this.fileChanged = false;
      this.file.push({
        name: "封面",
        url: "http://localhost:80" + cgrow.cover
      });
      this.editDialogVisible = true;
      this.editForm = cgrow;
    }
  }
};
</script>
<style  scoped>
.addUser {
  margin-left: 15px;
}
.el-form {
  margin: 0 auto;
}
.search {
  width: 500px;
}
.el-dialog .el-form-item:last-child {
  margin-left: 80px;
}
</style>